onClick:
{{(() => {
  const html = (appsmith.store.emailTemplateLiveHtml || (typeof RichTextTemplate.text === 'string' ? RichTextTemplate.text : ((appsmith.store.emailTemplateDraft || {}).html_template || '')));
  const root = document.createElement('div');
  root.innerHTML = html;
  const blocks = ['address','article','aside','blockquote','div','dl','fieldset','figcaption','figure','footer','form','h1','h2','h3','h4','h5','h6','header','hr','li','main','nav','ol','p','pre','section','table','tbody','td','tfoot','th','thead','tr','ul'];
  const pieces = [];
  const push = (value) => { if (value) pieces.push(value); };
  const ensureBreak = (count) => {
    if (!pieces.length) return;
    const last = pieces[pieces.length - 1] || '';
    let trailing = 0;
    for (let index = last.length - 1; index >= 0 && last[index] === '
'; index -= 1) {
      trailing += 1;
    }
    if (trailing >= count) return;
    pieces.push('
'.repeat(count - trailing));
  };
  const normalizeWhitespace = (value) => {
    const source = value || '';
    let output = '';
    let inWhitespace = false;
    for (let index = 0; index < source.length; index += 1) {
      const character = source[index];
      const isWhitespace = character === ' ' || character === '
' || character === '' || character === '	';
      if (isWhitespace) {
        if (!inWhitespace) output += ' ';
        inWhitespace = true;
      } else {
        output += character;
        inWhitespace = false;
      }
    }
    return output;
  };
  const trimLine = (value) => {
    let start = 0;
    let end = value.length;
    while (start < end && (value[start] === ' ' || value[start] === '	')) start += 1;
    while (end > start && (value[end - 1] === ' ' || value[end - 1] === '	')) end -= 1;
    return value.slice(start, end);
  };
  const collapseBlankLines = (value) => {
    const lines = value.split('
');
    const output = [];
    let blankRun = 0;
    for (let index = 0; index < lines.length; index += 1) {
      const line = trimLine(lines[index]);
      if (!line) {
        blankRun += 1;
        if (blankRun <= 1) output.push('');
      } else {
        blankRun = 0;
        output.push(line);
      }
    }
    return output.join('
').trim();
  };
  const walk = (node) => {
    if (!node) return;
    if (node.nodeType === Node.TEXT_NODE) {
      const value = normalizeWhitespace(node.textContent || '');
      if (value.trim()) push(value);
      return;
    }
    if (node.nodeType !== Node.ELEMENT_NODE) return;
    const tag = node.tagName.toLowerCase();
    if (tag === 'br') {
      ensureBreak(1);
      return;
    }
    if (tag === 'li') {
      ensureBreak(1);
      push('- ');
    }
    if (tag === 'hr') {
      ensureBreak(2);
      push('---');
      ensureBreak(2);
      return;
    }
    Array.from(node.childNodes || []).forEach(walk);
    if (tag === 'td' || tag === 'th') {
      push('	');
      return;
    }
    if (tag === 'li') {
      ensureBreak(1);
      return;
    }
    if (blocks.indexOf(tag) !== -1) {
      ensureBreak(2);
    }
  };
  Array.from(root.childNodes || []).forEach(walk);
  const text = collapseBlankLines(pieces.join(''));
  storeValue('emailTemplateDraft', { ...(appsmith.store.emailTemplateDraft || {}), text_template: text, html_template: html });
  storeValue('emailTemplateLiveHtml', html);
  resetWidget('TextareaTextTemplate', true);
  resetWidget('TextareaHtmlTemplate', true);
  resetWidget('RichTextPreview', true);
  showAlert('Plain text output updated', 'success');
})()}}
